import React, { useState, useEffect, useCallback } from "react";
import { useDocuments } from "../../hooks/useDocuments";
import type { Document } from "../Documents/document";
import PDFViewer from './PDFViewer';
import AudioPlayer from './AudioPlayer';
import TranscriptionEditor from './TranscriptionEditor';

const Transcription: React.FC = () => {
  const { documents, loading, error, updateDocumentWithVersioning } = useDocuments();
  
  // États simples
  const [activeTab, setActiveTab] = useState<'launch' | 'review' | 'tagging'>('launch');
  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [content, setContent] = useState('');
  const [lastSave, setLastSave] = useState<Date | null>(null);

  // Filtrer documents selon l'onglet
  const getDocumentsForTab = () => {
    return documents.filter(doc => {
      if (activeTab === 'launch') return doc.status === 'imported' || doc.status === 'transcribing';
      if (activeTab === 'review') return (doc.status === 'transcribed' || doc.status === 'reviewing') && doc.content?.trim();
      return doc.status === 'reviewed' || doc.status === 'tagging';
    });
  };

  const filteredDocs = getDocumentsForTab();

  // Charger contenu quand document sélectionné
  useEffect(() => {
    if (selectedDoc) {
      setContent(selectedDoc.content || '');
      // Restaurer brouillon si existe
      const draft = localStorage.getItem(`bcm_draft_${selectedDoc.id}`);
      if (draft) {
        const { content: savedContent } = JSON.parse(draft);
        if (savedContent && !selectedDoc.content) {
          setContent(savedContent);
        }
      }
    }
  }, [selectedDoc]);

  // Sauvegarde auto
  useEffect(() => {
    if (selectedDoc && content.trim()) {
      const timer = setTimeout(() => {
        localStorage.setItem(`bcm_draft_${selectedDoc.id}`, JSON.stringify({ content, timestamp: new Date().toISOString() }));
        setLastSave(new Date());
      }, 30000);
      return () => clearTimeout(timer);
    }
  }, [selectedDoc, content]);

  // Sauvegarder document
  const handleSave = useCallback(async () => {
    if (!selectedDoc || !content.trim()) {
      alert('⚠️ Le contenu ne peut pas être vide');
      return;
    }

    try {
      // Déterminer nouveau statut
      let newStatus = selectedDoc.status;
      if (activeTab === 'launch' && content.trim()) newStatus = 'transcribed';
      if (activeTab === 'review') newStatus = 'reviewed';
      if (activeTab === 'tagging') newStatus = 'tagged';

      await updateDocumentWithVersioning(selectedDoc.id, {
        ...selectedDoc,
        content,
        status: newStatus,
        progress: activeTab === 'launch' ? 40 : activeTab === 'review' ? 70 : 100,
      });

      // Nettoyer brouillon
      localStorage.removeItem(`bcm_draft_${selectedDoc.id}`);
      
      alert(`✅ Document sauvegardé !\nNouveau statut: ${newStatus}`);
      setSelectedDoc(null);
      setContent('');
    } catch (err) {
      console.error('Erreur sauvegarde:', err);
      alert('❌ Erreur lors de la sauvegarde');
    }
  }, [selectedDoc, content, activeTab, updateDocumentWithVersioning]);

  // Raccourcis clavier
  useEffect(() => {
    const handleKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setSelectedDoc(null);
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault();
        handleSave();
      }
    };
    window.addEventListener('keydown', handleKey);
    return () => window.removeEventListener('keydown', handleKey);
  }, [handleSave]);

  if (loading) return <div className="text-center py-12">Chargement...</div>;
  if (error) return <div className="text-red-500 p-4">Erreur: {error}</div>;

  // Aucun document sélectionné = afficher liste
  if (!selectedDoc) {
    return (
      <div className="container mx-auto px-4 py-6">
        <h1 className="text-2xl font-bold mb-6 flex items-center">
          <i className="fas fa-microphone mr-3 text-blue-500"></i>
          Module de Transcription
        </h1>
        
        {/* Sous-onglets */}
        <div className="mb-6 border-b">
          <div className="flex space-x-4">
            {[
              { key: 'launch', label: 'Lancement', icon: 'fa-rocket', color: 'blue' },
              { key: 'review', label: 'Relecture', icon: 'fa-eye', color: 'green' },
              { key: 'tagging', label: 'Tagging', icon: 'fa-tags', color: 'purple' }
            ].map(tab => (
              <button
                key={tab.key}
                onClick={() => setActiveTab(tab.key as any)}
                className={`flex items-center gap-2 px-4 py-3 font-medium ${
                  activeTab === tab.key
                    ? `text-${tab.color}-600 border-b-2 border-${tab.color}-600`
                    : 'text-gray-500 hover:text-gray-700'
                }`}
              >
                <i className={`fas ${tab.icon}`}></i>
                {tab.label}
                <span className={`ml-2 px-2 py-0.5 rounded-full text-xs ${
                  activeTab === tab.key ? `bg-${tab.color}-100 text-${tab.color}-800` : 'bg-gray-200'
                }`}>
                  {tab.key === 'launch' ? filteredDocs.length :
                   tab.key === 'review' ? documents.filter(d => (d.status === "transcribed" || d.status === "reviewing") && d.content?.trim()).length :
                   documents.filter(d => d.status === "reviewed" || d.status === "tagging").length}
                </span>
              </button>
            ))}
          </div>
        </div>

        {/* Liste documents */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          {filteredDocs.length === 0 ? (
            <div className="col-span-full text-center py-12">
              <div className="w-16 h-16 bg-gray-100 dark:bg-gray-700 rounded-full flex items-center justify-center mx-auto mb-4">
                <i className={`fas ${
                  activeTab === 'launch' ? 'fa-microphone-alt' :
                  activeTab === 'review' ? 'fa-eye' : 'fa-tags'
                } text-3xl text-gray-400`}></i>
              </div>
              <h3 className="text-lg font-medium mb-2">
                {activeTab === 'launch' && 'Aucun document à transcrire'}
                {activeTab === 'review' && 'Aucun document à relire'}
                {activeTab === 'tagging' && 'Aucun document à taguer'}
              </h3>
              <p className="text-gray-500">
                {activeTab === 'launch' && 'Importez des documents dans l\'onglet Documents'}
                {activeTab === 'review' && 'Terminez des transcriptions pour voir les documents ici'}
                {activeTab === 'tagging' && 'Validez des relectures pour voir les documents ici'}
              </p>
            </div>
          ) : (
            filteredDocs.map(doc => (
              <div
                key={doc.id}
                onClick={() => setSelectedDoc(doc)}
                className="border rounded-lg p-4 hover:border-blue-500 cursor-pointer transition"
              >
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold truncate">{doc.title}</h3>
                  <span className={`px-2 py-0.5 text-xs rounded-full ${
                    doc.status === 'imported' ? 'bg-yellow-100 text-yellow-800' :
                    doc.status === 'transcribing' ? 'bg-blue-100 text-blue-800' :
                    doc.status === 'transcribed' ? 'bg-green-100 text-green-800' :
                    doc.status === 'reviewing' ? 'bg-green-200 text-green-900' :
                    doc.status === 'reviewed' ? 'bg-purple-100 text-purple-800' : 'bg-purple-200 text-purple-900'
                  }`}>
                    {doc.status === 'imported' ? 'À transcrire' :
                     doc.status === 'transcribing' ? 'En cours' :
                     doc.status === 'transcribed' ? 'À relire' :
                     doc.status === 'reviewing' ? 'Relecture' :
                     doc.status === 'reviewed' ? 'À taguer' : 'Tagging'}
                  </span>
                </div>
                
                <div className="space-y-1 text-sm text-gray-600">
                  <div><i className="fas fa-file mr-2"></i>{doc.type}</div>
                  <div><i className="fas fa-database mr-2"></i>{doc.source}</div>
                  {doc.assigned_to && <div><i className="fas fa-user mr-2"></i>{doc.assigned_to}</div>}
                  {activeTab === 'review' && doc.content && (
                    <div className="text-blue-600"><i className="fas fa-font mr-2"></i>{doc.content.split(/\s+/).filter(w => w).length} mots</div>
                  )}
                </div>
                
                <button
                  onClick={(e) => { e.stopPropagation(); setSelectedDoc(doc); }}
                  className={`mt-3 w-full px-3 py-1.5 rounded text-sm font-medium ${
                    activeTab === 'launch' ? 'bg-blue-600 hover:bg-blue-700 text-white' :
                    activeTab === 'review' ? 'bg-green-600 hover:bg-green-700 text-white' :
                    'bg-purple-600 hover:bg-purple-700 text-white'
                  }`}
                >
                  {activeTab === 'launch' && 'Transcrire'}
                  {activeTab === 'review' && 'Relire'}
                  {activeTab === 'tagging' && 'Taguer'}
                </button>
              </div>
            ))
          )}
        </div>
      </div>
    );
  }

  // Document sélectionné = afficher interface édition
  return (
    <div className="container mx-auto px-4 py-6">
      {/* Header */}
      <div className="mb-6 flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold flex items-center">
            <i className={`fas ${
              activeTab === 'launch' ? 'fa-microphone text-blue-500' :
              activeTab === 'review' ? 'fa-eye text-green-500' : 'fa-tags text-purple-500'
            } mr-3`}></i>
            {activeTab === 'launch' && 'Transcription'}
            {activeTab === 'review' && 'Relecture'}
            {activeTab === 'tagging' && 'Tagging'}
            : {selectedDoc.title}
          </h1>
          <p className="text-gray-500">{selectedDoc.source} • {selectedDoc.assigned_to}</p>
        </div>
        <button
          onClick={() => setSelectedDoc(null)}
          className="px-4 py-2 bg-gray-200 hover:bg-gray-300 rounded flex items-center"
        >
          <i className="fas fa-arrow-left mr-2"></i>Retour à la liste
        </button>
      </div>

      {/* Interface édition - Layout simple vertical */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Panneau Média */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 h-[60vh] overflow-auto">
          <h2 className="font-bold mb-4 flex items-center">
            <i className={`fas ${
              selectedDoc.file_url?.match(/\.(mp3|wav|ogg|aac|m4a)$/) ? 'fa-headphones text-blue-500' :
              selectedDoc.file_url?.endsWith('.pdf') ? 'fa-file-pdf text-red-500' : 'fa-image text-green-500'
            } mr-2`}></i>
            {selectedDoc.file_url?.match(/\.(mp3|wav|ogg|aac|m4a)$/) ? 'Lecteur Audio' :
             selectedDoc.file_url?.endsWith('.pdf') ? 'Visualiseur PDF' : 'Image'}
          </h2>
          
          {selectedDoc.file_url?.match(/\.(mp3|wav|ogg|aac|m4a)$/) ? (
            <AudioPlayer audioUrl={selectedDoc.file_url} />
          ) : selectedDoc.file_url?.endsWith('.pdf') ? (
            <PDFViewer fileUrl={selectedDoc.file_url} />
          ) : selectedDoc.file_url ? (
            <img src={selectedDoc.file_url} alt="Document" className="max-w-full rounded" />
          ) : (
            <div className="text-center text-gray-500 py-8">
              <i className="fas fa-exclamation-triangle text-4xl mb-2"></i>
              <p>Aucun fichier attaché</p>
            </div>
          )}
        </div>

        {/* Panneau Éditeur */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 h-[60vh] flex flex-col">
          <h2 className="font-bold mb-4">Zone de saisie</h2>
          
          <TranscriptionEditor
            content={content}
            onChange={setContent}
            placeholder={
              activeTab === 'launch' ? "Commencez la transcription..." :
              activeTab === 'review' ? "Relisez et corrigez..." :
              "Ajoutez des tags et métadonnées..."
            }
          />
          
          {/* Barre d'actions fixe en bas */}
          <div className="mt-4 pt-4 border-t border-gray-200 flex justify-end gap-3">
            <button
              onClick={() => setSelectedDoc(null)}
              className="px-4 py-2 bg-gray-200 hover:bg-gray-300 rounded font-medium"
            >
              Annuler
            </button>
            <button
              onClick={handleSave}
              className={`px-4 py-2 rounded font-medium flex items-center ${
                activeTab === 'launch' ? 'bg-green-600 hover:bg-green-700 text-white' :
                activeTab === 'review' ? 'bg-yellow-500 hover:bg-yellow-600 text-white' :
                'bg-purple-600 hover:bg-purple-700 text-white'
              }`}
            >
              <i className={`fas ${
                activeTab === 'launch' ? 'fa-save' :
                activeTab === 'review' ? 'fa-check' : 'fa-tags'
              } mr-2`}></i>
              {activeTab === 'launch' && 'Sauvegarder et passer à la relecture'}
              {activeTab === 'review' && 'Valider la relecture'}
              {activeTab === 'tagging' && 'Finaliser le tagging'}
            </button>
          </div>
        </div>
      </div>

      {/* Barre d'état fixe en bas de page */}
      <div className="fixed bottom-0 left-0 right-0 bg-white dark:bg-gray-800 border-t py-2 px-6 shadow-lg">
        <div className="container mx-auto flex justify-between items-center text-sm">
          <div className="flex gap-6 text-gray-600">
            <span><i className="fas fa-font mr-1"></i>{content.split(/\s+/).filter(w => w).length} mots</span>
            <span><i className="fas fa-text-height mr-1"></i>{content.length} caractères</span>
          </div>
          <div className="text-gray-500">
            <i className={`fas fa-save mr-1 ${lastSave ? 'text-green-500' : 'text-gray-400'}`}></i>
            {lastSave ? `Dernière sauvegarde: ${new Date(lastSave).toLocaleTimeString()}` : 'Brouillon non sauvegardé'}
          </div>
          <div className="hidden md:block text-gray-400">
            <kbd className="px-2 py-0.5 bg-gray-200 rounded mr-1">Ctrl+S</kbd>Sauvegarder • 
            <kbd className="px-2 py-0.5 bg-gray-200 rounded mr-1">Echap</kbd>Fermer
          </div>
        </div>
      </div>
    </div>
  );
};

export default Transcription;
